// // This module generates a clock signal that is disabled when either the enable or test mode signals are high.
module zckenbuf_prim (clk, rclk, en_l, tm_l);
output clk;
input  rclk, en_l, tm_l;
reg    clken;
  always @ (rclk or en_l or tm_l)
    if (!rclk)  
      clken <= ~en_l | ~tm_l;
  assign clk = clken & rclk;
endmodule
